function fmtDate(d) {
  if (!d) return "";
  if (/^\d+$/.test(String(d))) {
    const dt = new Date(Number(d));
    return isNaN(dt) ? "" : dt.toISOString().slice(0,10);
  }
  const dt = new Date(d);
  return isNaN(dt) ? "" : dt.toISOString().slice(0,10);
}

function mdLink(text = "", url = "") {
  const cleanText = String(text).replace(/\r?\n/g, " ").replace(/[\[\]\(\)]/g, "");
  return url ? `[${cleanText}](${url})` : cleanText;
}

const tasks = getTasks($('Created Tasks').all());

// Group by original assignee (from t.task.assignee). Keep constructs otherwise.
const grouped = {};
for (const t of tasks) {
  const assignee = (t.task?.assignee || "Unassigned").trim() || "Unassigned";
  if (!grouped[assignee]) grouped[assignee] = [];
  const name = t.task?.name || t?.name || "Untitled task";
  const url  = t?.url || "";
  const due  = fmtDate(t?.due_date); // keeping your existing due-date source
  grouped[assignee].push(`  - ${mdLink(name, url)}${due ? ` _${due}_` : ""}`);
}

// Build two-level bullet list
const lines = [];
for (const assignee of Object.keys(grouped).sort()) {
  lines.push(`- ${assignee}`);
  // sort tasks under each assignee by their text for consistency
  lines.push(...grouped[assignee].sort());
}

return [{ json: { task_list: lines.join("\n") } }];

