function getTasks(items) {
  const out = [];
  for (const it of items) {
    const j = it.json;
    if (!j) continue;
    if (Array.isArray(j.data)) out.push(...j.data);
    else if (Array.isArray(j)) out.push(...j);
    else out.push(j);
  }
  return out;
}

function fmtDate(d) {
  if (!d) return "—";
  if (/^\d+$/.test(String(d))) {
    const dt = new Date(Number(d));
    if (!isNaN(dt)) return dt.toISOString().slice(0,10);
  }
  const dt = new Date(d);
  if (!isNaN(dt)) return dt.toISOString().slice(0,10);
  return String(d);
}

function escMD(s="") {
  return String(s).replace(/\|/g, "\\|").replace(/\r?\n/g, " ").trim();
}

function linkMD(text, url) {
  if (!url) return escMD(text);
  return `[${escMD(text)}](${url})`;
}

function linkSlack(text, url) {
  if (!url) return text;
  return `<${url}|${text.replace(/\|/g, " ").replace(/\r?\n/g, " ").trim()}>`;
}

const tasks = getTasks(items);

// Build rows
const rows = tasks.map(t => ({
